// O WhatsApp só libera o Criador (SuperAdmin) sem entrar. 
// Para pegar os outros, precisamos do retorno do nó de solicitação.
async function tryAlternativeAdminDetection(groupId) {
  const admins = [];
  try {
    // A maioria dos bots não consegue metadata sem estar dentro.
    // Mas o 'groupGetInviteInfo' ainda retorna o OWNER (Criador).
    const groupInfo = await nazu.groupGetInviteInfo(groupId.split('@')[0]);
    if (groupInfo && groupInfo.owner) {
        admins.push(groupInfo.owner); // O dono sempre é admin.
    }
  } catch (e) {
    console.log("Erro na detecção alternativa.");
  }
  return admins;
}

// --- FUNÇÃO DE QUERY DIRETA (AJUSTADA) ---
async function queryGroupAdminsDirectly(groupId) {
    try {
        // Tentamos ler o metadata "público". Se falhar, o WhatsApp bloqueou.
        const response = await nazu.groupMetadata(groupId);
        const admins = response.participants
            .filter(p => p.admin === 'admin' || p.admin === 'superadmin')
            .map(p => p.id);
        return { admins };
    } catch {
        return null; // Bloqueado pelo servidor
    }
}

