const sendImage = async (id, url, caption, quoted) => {
    let mentions = [];
    if (caption.includes('@')) {
        const words = caption.split(/ +/);
        for (let word of words) {
            if (word.includes('@')) mentions.push(identArroba(word));
        }
    }   
    return await nazu.sendMessage(id, { 
        image: { url: url }, 
        caption: caption, 
        mentions: mentions.length > 0 ? mentions : [sender] 
    }, { quoted: quoted });
}

